 char:"recep",charRu:"Секретарь",charEn:"Receptionist / Admin",scene:"Офисный звонок, блокнот и ручка, профессиональная обстановка",
 vocab:[["hold the line","подождите на линии · не кладите трубку"],["put on hold","поставить на удержание"],["transfer a call","перевести звонок в нужный отдел"],["voicemail","голосовая почта / автоответчик"],["leave a message","оставить сообщение · «Can I leave a message?»"],["call back","перезвонить · «I'll have him call you back»"],["missed call","пропущенный звонок"],["extension","добавочный номер · «Call extension 205»"],["conference call","конференц-звонок · несколько участников"],["mute","отключить микрофон · «You're on mute»"],["unmute","включить микрофон"],["screen share","демонстрация экрана"],["drop out","отключиться / потерять связь"],["poor connection","плохой сигнал · «You're breaking up»"],["freeze","зависнуть · изображение застыло"],["background noise","фоновый шум мешает разговору"],["agenda","повестка встречи · список тем"],["follow-up email","письмо по итогам встречи"],["action items","задачи с ответственным и сроком"],["minutes","протокол встречи · запись решений"],["RSVP","подтвердить участие в мероприятии"],["reschedule","перенести встречу · изменить дату"],["heads-up","предупредить заранее"],["loop in","включить кого-то в переписку"],["take offline","обсудить отдельно после звонка"],["breakout room","комната в Zoom · малые группы"],["recording","запись звонка"],["dial in","позвонить на конференцию по номеру"],["cancel","отменить встречу"],["bandwidth","пропускная способность · влияет на качество видео"]],
 qs:[["Good morning — how can I direct your call?","Доброе утро — как вас соединить?"],["Would you like to hold, leave a message, or call back later?","Подождёте, оставите сообщение или перезвоните?"],["Could you spell your name and give a callback number?","Назовите имя по буквам и номер для перезвонка?"],["Could you give a brief description so I can prioritise?","Кратко опишите вопрос — чтобы расставить приоритеты?"],["Before I transfer — anything else I should note?","Перед переводом — что ещё отметить?"],["Technical issues with the video platform — what alternative works?","Технические проблемы с платформой — что подходит в качестве замены?"]],
