 char:"officer",charRu:"Тренер / Капитан",charEn:"Coach / Team Captain",scene:"Спортивная площадка, команда в сборе перед игрой",
 vocab:[["match","матч / игра"],["score","счёт · «What's the score?»"],["half-time","перерыв между таймами · 15 минут"],["overtime","овертайм · добавочное время при ничье"],["penalty","пенальти · штрафной удар с 11 метров"],["referee","судья · следит за правилами"],["offside","вне игры · нарушение"],["foul","нарушение / фол · грубая игра"],["league","лига · команды играют между собой"],["championship","чемпионат · за звание чемпиона"],["qualifier","квалификационный матч · отбор в турнир"],["playoff","плей-офф · финальная стадия с выбыванием"],["final","финал · последний, решающий матч"],["trophy","трофей / кубок · награда победителям"],["MVP","самый ценный игрок (Most Valuable Player)"],["hike","поход / хайк · прогулка по природе"],["trail","тропа · обозначенный маршрут"],["summit","вершина · верхняя точка горы"],["altitude","высота над уровнем моря"],["terrain","рельеф / тип местности"],["camping","кемпинг · ночёвка с палаткой"],["gear","снаряжение · одежда и оборудование"],["marathon","марафон · 42.195 км"],["personal best","личный рекорд (PB)"],["triathlon","триатлон · плавание + велосипед + бег"],["sprint","спринт · короткий забег на максимуме"],["endurance","выносливость · длительная нагрузка"],["podium","пьедестал · 1-2-3 место"],["sportsmanship","спортивный дух · уважение к сопернику"],["warm-up","разминка · обязательна перед нагрузкой"]],
